def fibfib(n: int) -> int:
    """Compute the n-th FibFib number efficiently using matrix exponentiation."""
    if n == 0 or n == 1:
        return 0
    if n == 2:
        return 1

    # 3x3 transformation matrix
    M = ((1, 1, 1),
         (1, 0, 0),
         (0, 1, 0))

    def mat_mul(A, B):
        """Multiply two 3x3 matrices."""
        return tuple(
            tuple(
                A[i][0] * B[0][j] + A[i][1] * B[1][j] + A[i][2] * B[2][j]
                for j in range(3)
            )
            for i in range(3)
        )

    def mat_pow(mat, power):
        """Raise matrix to the given power."""
        # Identity matrix
        result = ((1, 0, 0),
                  (0, 1, 0),
                  (0, 0, 1))
        while power:
            if power & 1:
                result = mat_mul(result, mat)
            mat = mat_mul(mat, mat)
            power >>= 1
        return result

    # Compute M^(n-2)
    P = mat_pow(M, n - 2)

    # Base vector [f2, f1, f0] = [1, 0, 0]
    f2, f1, f0 = 1, 0, 0

    # Resulting first component = P[0][0]*f2 + P[0][1]*f1 + P[0][2]*f0
