def solution(a, b, n):
    def egcd(a, b):
        if b == 0:
            return a, 1, 0
        g, x1, y1 = egcd(b, a % b)
        return g, y1, x1 - (a // b) * y1

    if a == 0 and b == 0:
        return 'No solution' if n != 0 else ('x = ', 0, ', y = ', 0)

    if a == 0:
        if n % b == 0:
            y = n // b
            return ('x = ', 0, ', y = ', y) if y > 0 else 'No solution'
        return 'No solution'
    if b == 0:
        if n % a == 0:
            x = n // a
            return ('x = ', x, ', y = ', 0) if x > 0 else 'No solution'
        return 'No solution'

    g, s, t = egcd(abs(a), abs(b))
    if n % g != 0:
        return 'No solution'

    # adjust signs
    s *= (1 if a > 0 else -1)
    t *= (1 if b > 0 else -1)

    mult = n // g
    x0 = s * mult
    y0 = t * mult

    step_x = b // g
    step_y = a // g

    # find k such that x >= 1 and y >= 1
    # x = x0 + step_x * k
    # y = y0 - step_y * k
    import math
    lower = math.ceil((1 - x0) / step_x) if step_x != 0 else -10**18
    upper = math.floor((y0 - 1) / step_y) if step_y != 0 else 10**18

    if lower > upper:
        return 'No solution'

    k = lower
