        if len(path) == k:
            if not res or path < res:
                res = path
            continue
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < m and 0 <= ny < n and (nx, ny, tuple(path + [grid[nx][ny]])) not in visited:
