def minPath(grid, k):
    n = len(grid)
    positions = {}
    for i in range(n):
        for j in range(n):
            positions[grid[i][j]] = (i, j)
    all_vals = sorted(positions.keys())
    best = None
    for start_val in all_vals:
        r, c = positions[start_val]
        stack = [(r, c, [grid[r][c]], set([(r, c)]))]
        while stack:
            cr, cc, path, visited = stack.pop()
            if len(path) == k:
                if best is None or path < best:
                    best = path
                continue
            for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                nr, nc = cr + dr, cc + dc
                if 0 <= nr < n and 0 <= nc < n:
                    new_path = path + [grid[nr][nc]]
                    if best is not None and new_path >= best[:len(new_path)]:
                        continue
                    stack.append((nr, nc, new_path, visited | {(nr, nc)}))
        if best is not None and len(best) == k:
            break
    return best

