def tri(n):
    if n < 0:
        return []

    memo = {}

    def compute(k):
        if k in memo:
            return memo[k]
        if k == 1:
            res = 3
        elif k % 2 == 0:
            res = 1 + k // 2
        else:
            res = compute(k - 1) + compute(k - 2) + compute(k + 1)
        memo[k] = res
        return res

    result = []
    for i in range(n + 1):
        if i == 0:
            result.append(1)
        else:
            result.append(compute(i))
    return result
