def zigzag(n, k):
    if n == 0 and k == 0:
        return 1
    if k == 0:
        return 0
    if k > n:
        return 0
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1
    for i in range(1, n + 1):
