def get_maxgold(gold, m, n):
    dp = [[0] * n for _ in range(m)]
    for col in range(n - 1, -1, -1):
        for row in range(m):
            if col == n - 1:
                right = 0
            else:
                right = dp[row][col + 1]
            if row == 0 or col == n - 1:
                right_up = 0
            else:
                right_up = dp[row - 1][col + 1]
            if row == m - 1 or col == n - 1:
                right_down = 0
            else:
                right_down = dp[row + 1][col + 1]
            dp[row][col] = gold[row][col] + max(right, right_up, right_down)
    res = dp[0][0]
    for i in range(1, m):
        res = max(res, dp[i][0])
    return res
