def count_bidirectional(pairs):
    from collections import defaultdict
    count_map = defaultdict(int)
    bidirectional_count = 0
    for a, b in pairs:
        if count_map[(b, a)] > 0:
            bidirectional_count += 1
            count_map[(b, a)] -= 1
        else:
            count_map[(a, b)] += 1
    return str(bidirectional_count)
```

