def trim_tuple(lst, k):
    result = []
    for tup in lst:
        if 2 * k >= len(tup):
            trimmed = (tup[len(tup)//2],) if len(tup) % 2 == 1 else ()
        else:
            trimmed = tup[k:len(tup)-k]
        result.append(trimmed)
    return str([tuple(elem) if isinstance(elem, int) else elem for elem in result])
