def sumofFactors(n):
    total = 0
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            if i % 2 == 0:
                total += i
            if i != n // i and (n // i) % 2 == 0:
                total += n // i
    return total
```

