def check_Consecutive(lst):
    if not lst:
        return False
    min_val, max_val = min(lst), max(lst)
    if max_val - min_val + 1 != len(lst):
        return False
    seen = set()
    for num in lst:
        if num in seen:
            return False
        seen.add(num)
    return True
